#include <iostream>
#include <fstream>
#include <omp.h>

// Constants
const float GAMMA = 1.4f;
const int iterations = 2000;
const int block_length = 192;
const int NDIM = 3;
const int NNB = 4;
const int RK = 3;  // 3rd order RK
const float ff_mach = 1.2f;
const float deg_angle_of_attack = 0.0f;

// Variables
const int VAR_DENSITY = 0;
const int VAR_MOMENTUM = 1;
const int VAR_DENSITY_ENERGY = (VAR_MOMENTUM + NDIM);
const int NVAR = (VAR_DENSITY_ENERGY + 1);

// Function to compute flux contribution
void compute_flux_contribution(float& density, float momentum[3], float& density_energy, float& pressure, float velocity[3], float fc_momentum_x[3], float fc_momentum_y[3], float fc_momentum_z[3], float fc_density_energy[3]) {
    fc_momentum_x[0] = velocity[0] * momentum[0] + pressure;
    fc_momentum_x[1] = velocity[0] * momentum[1];
    fc_momentum_x[2] = velocity[0] * momentum[2];

    fc_momentum_y[0] = fc_momentum_x[1];
    fc_momentum_y[1] = velocity[1] * momentum[1] + pressure;
    fc_momentum_y[2] = velocity[1] * momentum[2];

    fc_momentum_z[0] = fc_momentum_x[2];
    fc_momentum_z[1] = fc_momentum_y[2];
    fc_momentum_z[2] = velocity[2] * momentum[2] + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy[0] = velocity[0] * de_p;
    fc_density_energy[1] = velocity[1] * de_p;
    fc_density_energy[2] = velocity[2] * de_p;
}

// Function to compute velocity
void compute_velocity(float& density, float momentum[3], float velocity[3]) {
    velocity[0] = momentum[0] / density;
    velocity[1] = momentum[1] / density;
    velocity[2] = momentum[2] / density;
}

// Function to compute speed squared
float compute_speed_sqd(float velocity[3]) {
    return velocity[0] * velocity[0] + velocity[1] * velocity[1] + velocity[2] * velocity[2];
}

// Function to compute pressure
float compute_pressure(float& density, float& density_energy, float& speed_sqd) {
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

// Function to compute speed of sound
float compute_speed_of_sound(float& density, float& pressure) {
    return sqrtf(GAMMA * pressure / density);
}

// Function to initialize variables
void initialize_variables(float* variables, int nelr) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        variables[i + VAR_DENSITY * nelr] = 1.4f;
        variables[i + (VAR_MOMENTUM + 0) * nelr] = 0.0f;
        variables[i + (VAR_MOMENTUM + 1) * nelr] = 0.0f;
        variables[i + (VAR_MOMENTUM + 2) * nelr] = 0.0f;
        variables[i + VAR_DENSITY_ENERGY * nelr] = 1.0f;
    }
}

// Function to compute step factor
void compute_step_factor(float* variables, float* areas, float* step_factors, int nelr) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density = variables[i + VAR_DENSITY * nelr];
        float momentum[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        float density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

        float velocity[3];
        compute_velocity(density, momentum, velocity);
        float speed_sqd = compute_speed_sqd(velocity);
        float pressure = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

// Function to compute flux
void compute_flux(float* variables, int* elements_surrounding_elements, float* normals, float* fluxes, int nelr) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density_i = variables[i + VAR_DENSITY * nelr];
        float momentum_i[3] = {variables[i + (VAR_MOMENTUM + 0) * nelr], variables[i + (VAR_MOMENTUM + 1) * nelr], variables[i + (VAR_MOMENTUM + 2) * nelr]};
        float density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

        float velocity_i[3];
        compute_velocity(density_i, momentum_i, velocity_i);
        float speed_sqd_i = compute_speed_sqd(velocity_i);
        float speed_i = sqrtf(speed_sqd_i);
        float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        float fc_i_momentum_x[3], fc_i_momentum_y[3], fc_i_momentum_z[3];
        float fc_i_density_energy[3];
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z, fc_i_density_energy);

        float flux_i_density = 0.0f;
        float flux_i_momentum[3] = {0.0f, 0.0f, 0.0f};
        float flux_i_density_energy = 0.0f;

        for (int j = 0; j < NNB; j++) {
            int nb = elements_surrounding_elements[i + j * nelr];
            float normal[3] = {normals[i + (j + 0 * NNB) * nelr], normals[i + (j + 1 * NNB) * nelr], normals[i + (j + 2 * NNB) * nelr]};
            float normal_len = sqrtf(normal[0] * normal[0] + normal[1] * normal[1] + normal[2] * normal[2]);

            if (nb >= 0) {
                float density_nb = variables[nb + VAR_DENSITY * nelr];
                float momentum_nb[3] = {variables[nb + (VAR_MOMENTUM + 0) * nelr], variables[nb + (VAR_MOMENTUM + 1) * nelr], variables[nb + (VAR_MOMENTUM + 2) * nelr]};
                float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

                float velocity_nb[3];
                compute_velocity(density_nb, momentum_nb, velocity_nb);
                float speed_sqd_nb = compute_speed_sqd(velocity_nb);
                float pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                float speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                float fc_nb_momentum_x[3], fc_nb_momentum_y[3], fc_nb_momentum_z[3];
                float fc_nb_density_energy[3];
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z, fc_nb_density_energy);

                float factor = -normal_len * 0.2f * 0.5f * (speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum[0] += factor * (momentum_i[0] - momentum_nb[0]);
                flux_i_momentum[1] += factor * (momentum_i[1] - momentum_nb[1]);
                flux_i_momentum[2] += factor * (momentum_i[2] - momentum_nb[2]);

                factor = 0.5f * normal[0];
                flux_i_density += factor * (momentum_nb[0] + momentum_i[0]);
                flux_i_density_energy += factor * (fc_nb_density_energy[0] + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[0] + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[0] + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[0] + fc_i_momentum_z[0]);

                factor = 0.5f * normal[1];
                flux_i_density += factor * (momentum_nb[1] + momentum_i[1]);
                flux_i_density_energy += factor * (fc_nb_density_energy[1] + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[1] + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[1] + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[1] + fc_i_momentum_z[1]);

                factor = 0.5f * normal[2];
                flux_i_density += factor * (momentum_nb[2] + momentum_i[2]);
                flux_i_density_energy += factor * (fc_nb_density_energy[2] + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (fc_nb_momentum_x[2] + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (fc_nb_momentum_y[2] + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (fc_nb_momentum_z[2] + fc_i_momentum_z[2]);
            } else if (nb == -1) {
                flux_i_momentum[0] += normal[0] * pressure_i;
                flux_i_momentum[1] += normal[1] * pressure_i;
                flux_i_momentum[2] += normal[2] * pressure_i;
            } else if (nb == -2) {
                float factor = 0.5f * normal[0];
                flux_i_density += factor * (0.0f + momentum_i[0]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[0]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[0]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[0]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[0]);

                factor = 0.5f * normal[1];
                flux_i_density += factor * (0.0f + momentum_i[1]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[1]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[1]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[1]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[1]);

                factor = 0.5f * normal[2];
                flux_i_density += factor * (0.0f + momentum_i[2]);
                flux_i_density_energy += factor * (0.0f + fc_i_density_energy[2]);
                flux_i_momentum[0] += factor * (0.0f + fc_i_momentum_x[2]);
                flux_i_momentum[1] += factor * (0.0f + fc_i_momentum_y[2]);
                flux_i_momentum[2] += factor * (0.0f + fc_i_momentum_z[2]);
            }
        }

        fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum[0];
        fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum[1];
        fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum[2];
        fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
    }
}

// Function to time step
void time_step(float* old_variables, float* variables, float* step_factors, float* fluxes, int nelr, int j) {
    #pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float factor = step_factors[i] / float(RK + 1 - j);

        variables[i + VAR_DENSITY * nelr] = old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
        variables[i + VAR_DENSITY_ENERGY * nelr] = old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
        variables[i + (VAR_MOMENTUM + 0) * nelr] = old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
        variables[i + (VAR_MOMENTUM + 1) * nelr] = old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
        variables[i + (VAR_MOMENTUM + 2) * nelr] = old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
    }
}

int main(int argc, char** argv) {
    if (argc < 2) {
        std::cout << "Specify data file name" << std::endl;
        return 0;
    }
    const char* data_file_name = argv[1];

    int nel;
    int nelr;

    // Read in domain geometry
    float* areas;
    int* elements_surrounding_elements;
    float* normals;
    {
        std::ifstream file(data_file_name);

        file >> nel;
        nelr = block_length * ((nel / block_length) + std::min(1, nel % block_length));

        float* h_areas = new float[nelr];
        int* h_elements_surrounding_elements = new int[nelr * NNB];
        float* h_normals = new float[nelr * NDIM * NNB];

        // Read in data
        for (int i = 0; i < nel; i++) {
            file >> h_areas[i];
            for (int j = 0; j < NNB; j++) {
                file >> h_elements_surrounding_elements[i + j * nelr];
                if (h_elements_surrounding_elements[i + j * nelr] < 0) h_elements_surrounding_elements[i + j * nelr] = -1;
                h_elements_surrounding_elements[i + j * nelr]--; // it's coming in with Fortran numbering

                for (int k = 0; k < NDIM; k++) {
                    file >> h_normals[i + (j + k * NNB) * nelr];
                    h_normals[i + (j + k * NNB) * nelr] = -h_normals[i + (j + k * NNB) * nelr];
                }
            }
        }

        // Fill in remaining data
        int last = nel - 1;
        for (int i = nel; i < nelr; i++) {
            h_areas[i] = h_areas[last];
            for (int j = 0; j < NNB; j++) {
                // Duplicate the last element
                h_elements_surrounding_elements[i + j * nelr] = h_elements_surrounding_elements[last + j * nelr];
                for (int k = 0; k < NDIM; k++) h_normals[last + (j + k * NNB) * nelr] = h_normals[last + (j + k * NNB) * nelr];
            }
        }

        areas = new float[nelr];
        for (int i = 0; i < nelr; i++) areas[i] = h_areas[i];

        elements_surrounding_elements = new int[nelr * NNB];
        for (int i = 0; i < nelr * NNB; i++) elements_surrounding_elements[i] = h_elements_surrounding_elements[i];

        normals = new float[nelr * NDIM * NNB];
        for (int i = 0; i < nelr * NDIM * NNB; i++) normals[i] = h_normals[i];

        delete[] h_areas;
        delete[] h_elements_surrounding_elements;
        delete[] h_normals;
    }

    // Create arrays and set initial conditions
    float* variables = new float[nelr * NVAR];
    initialize_variables(variables, nelr);

    float* old_variables = new float[nelr * NVAR];
    for (int i = 0; i < nelr * NVAR; i++) old_variables[i] = variables[i];

    float* fluxes = new float[nelr * NVAR];
    for (int i = 0; i < nelr * NVAR; i++) fluxes[i] = 0.0f;

    float* step_factors = new float[nelr];
    for (int i = 0; i < nelr; i++) step_factors[i] = 0.0f;

    // Make sure all memory is allocated before we start timing
    for (int i = 0; i < nelr * NVAR; i++) old_variables[i] = variables[i];
    for (int i = 0; i < nelr * NVAR; i++) fluxes[i] = 0.0f;
    for (int i = 0; i < nelr; i++) step_factors[i] = 0.0f;

    // Start timing
    double start_time = omp_get_wtime();

    // Begin iterations
    for (int i = 0; i < iterations; i++) {
        // Copy old variables
        for (int j = 0; j < nelr * NVAR; j++) old_variables[j] = variables[j];

        // Compute step factor
        compute_step_factor(variables, areas, step_factors, nelr);

        for (int j = 0; j < RK; j++) {
            // Compute flux
            compute_flux(variables, elements_surrounding_elements, normals, fluxes, nelr);

            // Time step
            time_step(old_variables, variables, step_factors, fluxes, nelr, j);
        }
    }

    // Stop timing
    double end_time = omp_get_wtime();

    // Print time
    std::cout << "Time: " << (end_time - start_time) / iterations << " seconds per iteration" << std::endl;

    // Save solution
    std::ofstream file("density");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY * nelr] << std::endl;

    file.close();

    file.open("momentum");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) {
        for (int j = 0; j < NDIM; j++) file << variables[i + (VAR_MOMENTUM + j) * nelr] << " ";
        file << std::endl;
    }

    file.close();

    file.open("density_energy");
    file << nel << " " << nelr << std::endl;
    for (int i = 0; i < nel; i++) file << variables[i + VAR_DENSITY_ENERGY * nelr] << std::endl;

    file.close();

    // Clean up
    delete[] areas;
    delete[] elements_surrounding_elements;
    delete[] normals;
    delete[] variables;
    delete[] old_variables;
    delete[] fluxes;
    delete[] step_factors;

    return 0;
}
